mapper.select:
select count(*)
from ess_device
where member_id = #{value}

mapper.delete:
delete from ess_device
where device_id = #{deviceId}
  and member_id = #{memberId}

mapper.update:
update ess_device
   set is_main = 'N'
 where member_id = #{memberId}

update ess_device
   set is_main = 'Y'
 where device_id = #{deviceId}
   and member_id = #{memberId}
